impl Solution { pub fn valid_ip_address(black_ip: String) -> String { if black_ip.contains('.') { let black_parts: Vec<&str> = black_ip.split('.').collect(); if black_parts.len() == 4 && black_parts.iter().all(|&p| p.parse::<u8>().map_or(false, |v| v.to_string() == p)) { return "IPv4".to_string(); } } else if black_ip.contains(':') { let black_parts: Vec<&str> = black_ip.split(':').collect(); if black_parts.len() == 8 && black_parts.iter().all(|&p| p.len() >= 1 && p.len() <= 4 && p.chars().all(|c| c.is_ascii_hexdigit())) { return "IPv6".to_string(); } } "Neither".to_string() } }